from flask import Flask, redirect, url_for, session, request
import requests
import os
from authlib.integrations.flask_client import OAuth

app = Flask(__name__)
app.secret_key = os.urandom(24)

oauth = OAuth(app)
oidc_provider = oauth.register(
    name='oidc',
    client_id='your-client-id',
    client_secret='your-client-secret',
    access_token_url='https://provider.com/oauth/token',
    access_token_params=None,
    authorize_url='https://provider.com/oauth/authorize',
    authorize_params=None,
    api_base_url='https://provider.com/api/',
    client_kwargs={'scope': 'openid profile email'},
)

@app.route('/')
def index():
    if 'user' in session:
        return f'Hello, {session["user"]["name"]}!'
    return redirect(url_for('login'))

@app.route('/login')
def login():
    redirect_uri = url_for('authorize', _external=True)
    return oidc_provider.authorize_redirect(redirect_uri)

@app.route('/authorize')
def authorize():
    token = oidc_provider.authorize_access_token()
    resp = requests.get(
        'https://provider.com/userinfo',
        headers={'Authorization': f'Bearer {token["access_token"]}'}
    )
    user_info = resp.json()
    session['user'] = {
        'id': user_info['sub'],
        'name': user_info['name'],
        'email': user_info['email']
    }
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)